import React, { useEffect, useRef } from 'react';

const VideoFrame = ({ src, onError }) => {
  const containerRef = useRef(null);

  useEffect(() => {
    if (src && containerRef.current) {
      // Crear iframe de forma muy básica para evitar detección
      const frame = document.createElement('iframe');

      // Solo atributos esenciales
      frame.src = src;
      frame.width = '100%';
      frame.height = '100%';
      frame.allowFullscreen = true;

      // Estilos básicos sin transformaciones
      frame.style.cssText = `
        border: none;
        background: #000;
        border-radius: 8px;
        width: 100%;
        height: 100%;
      `;

      // Limpiar y agregar
      containerRef.current.innerHTML = '';
      containerRef.current.appendChild(frame);

      // No intentar inyectar CSS por CORS
      frame.onload = () => {
        console.log('Iframe cargado');
      };

      // Verificar si carga
      const checkLoad = setTimeout(() => {
        try {
          if (!frame.contentWindow) {
            console.log('Iframe no cargó correctamente');
            if (onError) onError();
          }
        } catch (e) {
          console.log('Error verificando iframe:', e.message);
          if (onError) onError();
        }
      }, 5000);

      return () => {
        clearTimeout(checkLoad);
        if (containerRef.current) {
          containerRef.current.innerHTML = '';
        }
      };
    }
  }, [src, onError]);

  return (
    <div 
      ref={containerRef}
      className="w-full h-96 md:h-[500px] lg:h-[600px] bg-black rounded-lg relative overflow-hidden"
      style={{ 
        minHeight: '400px'
      }}
    >
      {/* Máscara para ocultar elementos no deseados */}
      <div className="absolute inset-0 pointer-events-none z-10">
        {/* Ocultar parte superior */}
        <div className="absolute top-0 left-0 right-0 h-12 bg-black"></div>
        {/* Ocultar parte inferior */}
        <div className="absolute bottom-0 left-0 right-0 h-20 bg-black"></div>
        {/* Ocultar laterales */}
        <div className="absolute top-0 bottom-0 left-0 w-8 bg-black"></div>
        <div className="absolute top-0 bottom-0 right-0 w-8 bg-black"></div>
      </div>
    </div>
  );
};

export default VideoFrame;
